const http = require('http');
const crypto = require('crypto');
const express = require('express');
const { Server } = require('socket.io');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24; // 24 hours

const users = new Map(); // username -> { passwordHash, salt, score, sessionToken, sessionExpiresAt }
const sessions = new Map(); // token -> { username, expiresAt }
const connectedPlayers = new Map(); // socket.id -> { username, token }

function hashPassword(password, salt) {
  return crypto.pbkdf2Sync(String(password), salt, 100000, 64, 'sha512').toString('hex');
}

function createSession(username) {
  const token = crypto.randomBytes(32).toString('hex');
  const expiresAt = Date.now() + SESSION_TTL_MS;
  sessions.set(token, { username, expiresAt });
  const user = users.get(username);
  user.sessionToken = token;
  user.sessionExpiresAt = expiresAt;
  return { token, expiresAt };
}

function verifySession(token) {
  if (!token || typeof token !== 'string') return null;
  const session = sessions.get(token);
  if (!session) return null;
  if (Date.now() > session.expiresAt) {
    sessions.delete(token);
    const user = users.get(session.username);
    if (user && user.sessionToken === token) {
      user.sessionToken = null;
      user.sessionExpiresAt = 0;
    }
    return null;
  }
  return session.username;
}

function requireAuth(socket, next) {
  const token = socket.handshake.auth?.token || socket.handshake.headers['x-session-token'];
  const username = verifySession(token);
  if (!username) {
    return next(new Error('Unauthorized'));
  }
  socket.data.username = username;
  socket.data.token = token;
  return next();
}

function normalizeUsername(username) {
  return String(username || '').trim().toLowerCase();
}

function isValidUsername(username) {
  return /^[a-zA-Z0-9_]{3,20}$/.test(username);
}

function isValidPassword(password) {
  return typeof password === 'string' && password.length >= 6 && password.length <= 128;
}

function isValidScore(score) {
  return Number.isFinite(score) && score >= 0 && score <= Number.MAX_SAFE_INTEGER;
}

function cleanupExpiredSessions() {
  const now = Date.now();
  for (const [token, session] of sessions.entries()) {
    if (now > session.expiresAt) {
      sessions.delete(token);
      const user = users.get(session.username);
      if (user && user.sessionToken === token) {
        user.sessionToken = null;
        user.sessionExpiresAt = 0;
      }
    }
  }
}

setInterval(cleanupExpiredSessions, 60 * 1000).unref();

