io.use(requireAuth);

io.on('connection', (socket) => {
  const username = socket.data.username;
  connectedPlayers.set(socket.id, { username, token: socket.data.token });

  socket.emit('authenticated', {
    username,
    score: users.get(username)?.score || 0
  });

  socket.on('joinGame', () => {
    socket.emit('gameJoined', { username });
  });

  socket.on('move', (payload = {}, ack) => {
    const move = String(payload.move || '').trim();

    if (!move) {
      if (typeof ack === 'function') ack({ ok: false, error: 'Invalid move' });
      return;
    }

    socket.broadcast.emit('playerMoved', {
      username,
      move,
      at: Date.now()
    });

    if (typeof ack === 'function') ack({ ok: true });
  });

  socket.on('submitScore', (payload = {}, ack) => {
    const reportedScore = Number(payload.score);

    if (!isValidScore(reportedScore)) {
      if (typeof ack === 'function') ack({ ok: false, error: 'Invalid score' });
      return;
    }

    const user = users.get(username);
    if (!user) {
      if (typeof ack === 'function') ack({ ok: false, error: 'User not found' });
      return;
    }

    user.score = reportedScore;

    io.emit('leaderboardUpdated', {
      leaderboard: [...users.entries()]
        .map(([u, data]) => ({ username: u, score: data.score }))
        .sort((a, b) => b.score - a.score)
        .slice(0, 100)
    });

    if (typeof ack === 'function') ack({ ok: true, score: user.score });
  });

  socket.on('disconnect', () => {
    connectedPlayers.delete(socket.id);
  });
});

